('校园头条', 1),
('校园公告', 2),
('学术讲座', 3),
('社团活动', 4),
('文体赛事', 5),
('就业信息', 6),
('学习资源', 7),
('校园服务', 8);
INSERT INTO news (`title`, `description`, `content`, `image`, `author`, `category_id`, `views`, `publish_time`) VALUES
('2025年秋季学期开学通知', '学校发布开学安排，新生报到时间确定', '教务处发布2025年秋季学期开学通知。全体学生于9月1日正式上课，新生报到时间为8月30日至31日。请同学们提前做好返校准备，注意交通安全。开学第一周将进行教学检查，请各学院做好相关准备工作。', 'https://picsum.photos/id/200/200/200', '教务处', 2, 5000, '2025-08-25 09:00:00'),
('人工智能学术讲座预告', '知名教授将带来前沿AI技术分享', '计算机学院邀请清华大学张明教授来校进行学术讲座。讲座主题为"人工智能前沿技术与应用展望"，将探讨大模型、计算机视觉等热门领域。时间：9月5日下午2点，地点：学术报告厅。欢迎师生参加。', 'https://picsum.photos/id/201/200/200', '计算机学院', 3, 3200, '2025-08-26 14:00:00'),
('迎新晚会节目征集', '期待你的精彩表演', '学生会启动2025年迎新晚会节目征集工作。节目形式不限，包括歌曲、舞蹈、相声、小品、乐器演奏等。报名截止日期：9月10日。欢迎新老同学积极参与，展现才艺。', 'https://picsum.photos/id/202/200/200', '学生会', 4, 2800, '2025-08-27 10:00:00'),
('校园招聘会即将举行', '50家企业提供千余岗位', '学校将于9月15日举办秋季校园招聘会。已有50家知名企业报名参会，提供IT、金融、制造、教育等多个领域的岗位超过1000个。请毕业生提前准备简历，积极参与。', 'https://picsum.photos/id/203/200/200', '就业指导中心', 6, 4500, '2025-08-28 11:00:00'),
('图书馆新增电子资源', '知网、万方等数据库已开通', '图书馆新增多种电子资源，包括中国知网、万方数据、维普资讯等全文数据库，以及IEEE、ACM等外文数据库。在校师生可通过校园网免费访问这些资源。详细使用指南请查看图书馆网站。', 'https://picsum.photos/id/204/200/200', '图书馆', 7, 2100, '2025-08-29 16:00:00'),
('校园篮球赛火热开赛', '各学院代表队激烈角逐', '第20届校园篮球联赛正式开赛。来自12个学院的代表队将进行为期一个月的比赛。首场比赛将于9月3日在体育馆举行，欢迎师生前往观赛加油。', 'https://picsum.photos/id/205/200/200', '体育部', 5, 1800, '2025-08-30 08:30:00'),
('食堂推出新学期菜单', '新增特色菜品广受好评', '新学期食堂推出全新菜单，新增川菜、粤菜等特色窗口，以及营养早餐系列。食堂还将提供外卖服务，同学们可以通过校园APP订餐。欢迎同学们品尝并提出宝贵意见。', 'https://picsum.photos/id/206/200/200', '后勤处', 8, 3400, '2025-08-31 12:00:00'),
('校园卡充值系统升级', '支持支付宝微信支付', '校园卡充值系统完成升级，现在支持支付宝和微信支付。同学们可以通过校园APP或自助充值机进行充值，无需再去充值窗口排队。系统还新增了消费明细查询功能。', 'https://picsum.photos/id/207/200/200', '信息中心', 8, 4100, '2025-09-01 10:00:00'),
('新生入学教育安排', '帮助新生快速适应校园生活', '学生处安排了丰富的新生入学教育活动，包括校史校情教育、安全教育、学业规划指导、心理健康讲座等。活动时间：9月1日至5日。请新生按时参加各项活动。', 'https://picsum.photos/id/208/200/200', '学生处', 2, 3800, '2025-09-01 14:00:00'),
('创新创业大赛报名开始', '最高奖金5万元', '学校举办2025年创新创业大赛，鼓励学生开展科技创新和创业实践。大赛设创意组、创业组两个组别，最高奖金5万元。报名截止日期：10月15日。详情请关注创新创业学院网站。', 'https://picsum.photos/id/209/200/200', '创新创业学院', 3, 2500, '2025-09-02 09:00:00'),
('校园音乐节即将举办', '知名乐队倾情演出', '第三届校园音乐节将于9月20日在中心广场举行。届时将有5支知名乐队和多位校园歌手登台献艺。门票免费，先到先得。活动由校团委主办，欢迎师生参与。', 'https://picsum.photos/id/210/200/200', '校团委', 4, 5200, '2025-09-03 15:00:00'),
('考研辅导讲座通知', '专家指导备考策略', '研究生院将举办考研辅导系列讲座，邀请考研辅导专家为同学们讲解备考策略、复习方法和心态调整。第一场讲座将于9月8日晚上7点在教学楼A座101教室举行。', 'https://picsum.photos/id/211/200/200', '研究生院', 7, 3600, '2025-09-04 11:30:00'),
('秋季运动会筹备中', '期待同学们踊跃报名', '2025年秋季运动会将于10月20日至22日举行。目前各项筹备工作正在进行中，运动员报名通道已开启。欢迎同学们积极参与，展现青春风采。', 'https://picsum.photos/id/212/200/200', '体育部', 5, 2200, '2025-09-05 10:00:00'),
('校园安全温馨提示', '注意防盗防骗', '保卫处温馨提示：新学期开始，校园人流量增加，请同学们注意财物安全，离开宿舍时锁好门窗，不要将贵重物品随意放置。同时提高警惕，防范电信诈骗。', 'https://picsum.photos/id/213/200/200', '保卫处', 2, 3900, '2025-09-05 16:00:00'),
('校友返校日活动安排', '欢迎校友回家', '学校将于10月1日举办校友返校日活动，欢迎各届校友重返母校。活动包括校史馆参观、校友座谈会、文艺演出等。详情请关注校友会公众号。', 'https://picsum.photos/id/214/200/200', '校友会', 4, 1800, '2025-09-06 09:00:00'),
('学术期刊投稿讲座', '提升论文发表成功率', '图书馆邀请期刊编辑来校开展学术论文写作与投稿讲座，帮助同学们了解期刊投稿流程和技巧，提高论文发表成功率。时间：9月12日下午3点，地点：图书馆报告厅。', 'https://picsum.photos/id/215/200/200', '图书馆', 7, 1500, '2025-09-07 14:00:00'),
('校园志愿者招募', '传递爱心服务社会', '校志愿者协会启动新学期志愿者招募工作。志愿服务项目包括社区支教、环保公益、赛事服务等。报名时间：9月1日至20日。加入我们，用行动传递爱心。', 'https://picsum.photos/id/216/200/200', '志愿者协会', 4, 2900, '2025-09-08 10:00:00'),
('校园Wi-Fi全覆盖', '网速提升至100Mbps', '信息中心完成校园Wi-Fi升级改造，实现全校Wi-Fi全覆盖，网速提升至100Mbps。同学们可以使用学号和密码登录校园Wi-Fi，享受高速网络服务。', 'https://picsum.photos/id/217/200/200', '信息中心', 8, 4600, '2025-09-09 11:00:00'),
('心理健康咨询服务', '为你的心灵保驾护航', '心理咨询中心新学期继续为同学们提供免费心理咨询服务。咨询方式包括面对面咨询、电话咨询和网络咨询。开放时间：周一至周五8:00-17:00。', 'https://picsum.photos/id/218/200/200', '心理咨询中心', 8, 1200, '2025-09-10 14:00:00'),
('校园十佳歌手大赛', '唱出青春旋律', '第十届校园十佳歌手大赛报名开始。比赛分为初赛、复赛和决赛三个阶段，决赛将于11月举行。无论你是流行、民谣还是美声，只要热爱唱歌，都可以报名参加。', 'https://picsum.photos/id/219/200/200', '学生会', 5, 3100, '2025-09-11 09:00:00'),
('校企合作项目发布', '提供实习就业机会', '学校与10家知名企业签署校企合作协议，将为同学们提供更多实习和就业机会。合作企业包括华为、腾讯、阿里巴巴等行业领军企业。详情请咨询就业指导中心。', 'https://picsum.photos/id/220/200/200', '就业指导中心', 6, 4200, '2025-09-12 10:30:00'),
('校园环保活动', '共建绿色校园', '环保协会发起"绿色校园"主题活动，包括垃圾分类宣传、绿植领养、旧物回收等。活动期间将举办环保知识竞赛，获胜者可获得精美礼品。', 'https://picsum.photos/id/221/200/200', '环保协会', 4, 2300, '2025-09-13 15:00:00'),
('学术沙龙系列活动', '促进学术交流', '研究生院将举办系列学术沙龙活动，每周邀请不同领域的专家学者分享最新研究成果。首场沙龙主题为"数字化转型与未来教育"，时间：9月18日下午4点。', 'https://picsum.photos/id/222/200/200', '研究生院', 3, 1700, '2025-09-14 11:00:00'),
('校园宿舍文明评比', '共创和谐居住环境', '学生处开展宿舍文明评比活动，评选"文明宿舍"和"优秀宿舍长"。评比内容包括卫生整洁、安全规范、文化氛围等。获奖宿舍将获得荣誉证书和物质奖励。', 'https://picsum.photos/id/223/200/200', '学生处', 2, 2600, '2025-09-15 09:00:00'),
('校园招聘会企业名单公布', '提前了解招聘信息', '秋季校园招聘会企业名单已公布，包括50家知名企业。同学们可以在就业指导中心网站查看详细信息，提前了解各企业的招聘岗位和要求，做好应聘准备。', 'https://picsum.photos/id/224/200/200', '就业指导中心', 6, 3800, '2025-09-16 14:00:00'),
('校园电影放映活动', '每周免费观影', '学生会每周五晚在大学生活动中心举办免费电影放映活动。本周放映《肖申克的救赎》，下周五放映《阿甘正传》。欢迎同学们前来观看，感受经典魅力。', 'https://picsum.photos/id/225/200/200', '学生会', 4, 2000, '2025-09-17 10:00:00'),
('校园网络安全宣传周', '提升安全意识', '信息中心举办网络安全宣传周活动，包括网络安全讲座、知识竞赛、海报展览等。旨在提高同学们的网络安全意识，防范网络诈骗和信息泄露。', 'https://picsum.photos/id/226/200/200', '信息中心', 2, 2400, '2025-09-18 09:00:00'),
('校园开放日活动', '欢迎中学生参观', '学校将于10月15日举办校园开放日活动，欢迎周边中学的师生和家长前来参观。活动包括校园游览、实验室参观、招生咨询等。让更多人了解我们的学校。', 'https://picsum.photos/id/227/200/200', '招生办公室', 4, 1600, '2025-09-19 15:00:00'),
('校园美食节', '品尝各地风味', '后勤处将举办校园美食节活动，汇聚各地特色美食，包括四川火锅、广东点心、陕西面食等。活动时间：9月25日至27日，地点：食堂广场。欢迎同学们前来品尝。', 'https://picsum.photos/id/228/200/200', '后勤处', 8, 4900, '2025-09-20 11:00:00'),
('校园读书节', '书香满校园', '图书馆举办校园读书节活动，包括读书分享会、好书推荐、征文比赛等。活动期间借阅图书可享受双倍积分。让阅读成为一种习惯。', 'https://picsum.photos/id/229/200/200', '图书馆', 7, 1900, '2025-09-21 09:00:00'),
('校园头条：开学典礼隆重举行', '校长发表重要讲话', '2025年秋季学期开学典礼在体育馆隆重举行。校长在讲话中勉励全体学生要志存高远、脚踏实地，努力成为德智体美劳全面发展的新时代青年。', 'https://picsum.photos/id/230/200/200', '校办公室', 1, 8500, '2025-09-01 08:00:00'),
('校园头条：新增人工智能专业', '培养AI领域人才', '教育部批准我校新增人工智能本科专业，将于2026年开始招生。该专业将培养具备人工智能理论基础和实践能力的高素质人才，满足社会对AI人才的需求。', 'https://picsum.photos/id/231/200/200', '教务处', 1, 6200, '2025-09-02 10:00:00'),
('校园头条：科研团队取得重大突破', '发表Nature论文', '我校科研团队在量子计算领域取得重大突破，相关研究成果发表在国际顶级期刊Nature上。这是我校首次以第一单位在Nature发表论文，标志着我校科研水平迈上了新台阶。', 'https://picsum.photos/id/232/200/200', '科研处', 1, 7100, '2025-09-03 16:00:00'),
('校园头条：获国家级教学成果奖', '教学改革成效显著', '我校申报的教学成果"基于产教融合的应用型人才培养模式改革"荣获国家级教学成果一等奖。这是对我校教学改革工作的充分肯定。', 'https://picsum.photos/id/233/200/200', '教务处', 1, 5800, '2025-09-04 14:00:00'),
('校园头条：校园建设新进展', '图书馆新馆即将开放', '图书馆新馆建设进入收尾阶段，预计将于10月中旬正式开放。新馆建筑面积2万平方米，可容纳3000名读者同时阅读，配备先进的智能管理系统。', 'https://picsum.photos/id/234/200/200', '基建处', 1, 6500, '2025-09-05 11:00:00'),
('学术讲座：大数据时代的隐私保护', '专家解读热点问题', '法学院邀请北京大学王教授来校开展学术讲座，主题为"大数据时代的个人隐私保护"。讲座将探讨数据隐私保护的法律框架和技术手段。时间：9月20日下午2点。', 'https://picsum.photos/id/235/200/200', '法学院', 3, 2100, '2025-09-16 10:00:00'),
('学术讲座：新能源技术发展趋势', '探讨可持续发展', '能源学院举办学术讲座，邀请中国科学院院士李教授分享新能源技术的最新发展趋势和应用前景。讲座将重点介绍太阳能、风能等清洁能源的发展现状和未来方向。', 'https://picsum.photos/id/236/200/200', '能源学院', 3, 2800, '2025-09-18 14:00:00'),
('社团活动：动漫社招新', '热爱动漫的你快来加入', '动漫社开始招新啦！我们有精彩的cosplay表演、动漫观影会、绘画比赛等活动。无论你是二次元爱好者还是想了解动漫文化，都欢迎加入我们的大家庭。', 'https://picsum.photos/id/237/200/200', '动漫社', 4, 1500, '2025-09-08 12:00:00'),
('社团活动：辩论社挑战赛', '展现口才与智慧', '辩论社举办新生挑战赛，欢迎新生报名参加。比赛采用淘汰赛制，获胜队伍将代表学校参加省赛。报名截止日期：9月20日。', 'https://picsum.photos/id/238/200/200', '辩论社', 4, 1900, '2025-09-10 10:00:00'),
('文体赛事：羽毛球锦标赛', '谁是校园羽球之王', '第15届校园羽毛球锦标赛将于9月25日至27日举行。比赛设单打、双打、混双三个项目，欢迎各学院同学报名参赛。', 'https://picsum.photos/id/239/200/200', '体育部', 5, 2200, '2025-09-12 09:00:00'),
('文体赛事：校园足球联赛', '绿茵场上展风采', '校园足球联赛即将开赛，12支学院代表队将展开激烈角逐。首场比赛将于9月20日进行，欢迎同学们到现场为支持的球队加油助威。', 'https://picsum.photos/id/240/200/200', '体育部', 5, 1800, '2025-09-15 10:00:00'),
('就业信息：华为校园招聘', '提供众多优质岗位', '华为公司将于9月20日来校举办专场招聘会，招聘软件工程师、硬件工程师、产品经理等多个岗位。要求本科及以上学历，计算机、通信等相关专业。', 'https://picsum.photos/id/241/200/200', '就业指导中心', 6, 5600, '2025-09-17 14:00:00'),
('就业信息：公务员考试指导', '助力考公之路', '学校邀请公务员考试专家来校开展备考指导讲座，涵盖行测、申论等科目。讲座时间：9月22日下午2点，地点：教学楼B座201教室。', 'https://picsum.photos/id/242/200/200', '就业指导中心', 6, 3400, '2025-09-19 11:00:00'),
('学习资源：MOOC课程推荐', '提升专业技能', '图书馆推荐一批优质MOOC课程，包括Coursera、edX等平台的热门课程。同学们可以利用课余时间学习，获取专业知识和技能。学习完成后可获得证书。', 'https://picsum.photos/id/243/200/200', '图书馆', 7, 2600, '2025-09-21 10:00:00'),
('学习资源：数据库培训', '掌握数据管理技能', '信息中心将举办数据库应用培训，内容包括SQL基础、MySQL操作、数据查询优化等。培训时间：每周六上午9点至11点，共4周。报名请联系信息中心。', 'https://picsum.photos/id/244/200/200', '信息中心', 7, 1700, '2025-09-22 09:00:00'),
('校园服务：快递服务升级', '新增智能快递柜', '后勤处新增10组智能快递柜，分布在各宿舍楼楼下。同学们可以24小时取件，无需再排队等待。快递柜支持扫码取件和人脸识别。', 'https://picsum.photos/id/245/200/200', '后勤处', 8, 4300, '2025-09-23 12:00:00'),
('校园服务：医疗服务优化', '新增夜间急诊', '校医院优化医疗服务，新增夜间急诊服务，时间为晚上8点至次日早上8点。急诊范围包括发热、外伤、急症等。同学们如有紧急情况可拨打校医院电话。', 'https://picsum.photos/id/246/200/200', '校医院', 8, 2900, '2025-09-24 10:00:00'),
('校园公告：国庆节放假安排', '假期安全提示', '根据国家法定节假日安排，国庆节放假时间为10月1日至7日，共7天。请同学们合理安排假期，离校前注意关闭宿舍电源和门窗。返校时间为10月8日。', 'https://picsum.photos/id/247/200/200', '校办公室', 2, 6100, '2025-09-25 09:00:00'),
('校园公告：奖学金评定通知', '符合条件的同学请申请', '学生处发布2025年秋季学期奖学金评定通知。国家奖学金、国家励志奖学金、校级奖学金等均开始接受申请。申请截止日期：10月10日。', 'https://picsum.photos/id/248/200/200', '学生处', 2, 4800, '2025-09-26 14:00:00');